{
  "version": "2.0.0",
  "inputs": [
    {
      "id": "gtagsSymbol",
      "type": "promptString",
      "description": "Symbol name (e.g. init_binderfs)",
      "default": ""
    }
  ],
  "tasks": [
    {
      "label": "gtags: index (binder drivers)",
      "type": "shell",
      "command": "${workspaceFolder}/tools/gtags-index.sh android-drivers",
      "problemMatcher": [],
      "presentation": {
        "reveal": "always",
        "panel": "shared"
      }
    },
    {
      "label": "gtags: index (all C/C++)",
      "type": "shell",
      "command": "${workspaceFolder}/tools/gtags-index.sh all",
      "problemMatcher": [],
      "presentation": {
        "reveal": "always",
        "panel": "shared"
      }
    },
    {
      "label": "gtags: go to definition (selection)",
      "type": "shell",
      "command": "${workspaceFolder}/tools/global-goto.sh ${selectedText}",
      "options": {
        "cwd": "${fileDirname}"
      },
      "problemMatcher": [],
      "presentation": {
        "reveal": "silent",
        "panel": "shared",
        "close": true
      }
    },
    {
      "label": "gtags: go to definition (prompt)",
      "type": "shell",
      "command": "${workspaceFolder}/tools/global-goto.sh ${input:gtagsSymbol}",
      "options": {
        "cwd": "${fileDirname}"
      },
      "problemMatcher": [],
      "presentation": {
        "reveal": "silent",
        "panel": "shared",
        "close": true
      }
    }
  ]
}
